import React, { useEffect, useRef, useState } from 'react';
import { Briefcase } from 'lucide-react';

interface ExperienceItem {
  company: string;
  role: string;
  period: string;
  side: 'left' | 'right';
}

const experiences: ExperienceItem[] = [
  {
    company: 'Compass UOL',
    role: 'Estagiária em Desenvolvimento Full-Stack',
    period: 'Março 2025 – Agosto 2025',
    side: 'left',
  },
  {
    company: 'iBico Brasil',
    role: 'Engenheira de Software',
    period: 'Novembro 2025 – Atual',
    side: 'right',
  },
];

function TimelineCard({ item, index }: { item: ExperienceItem; index: number }) {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.unobserve(el);
        }
      },
      { threshold: 0.2 }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  const isLeft = item.side === 'left';

  return (
    <div
      ref={ref}
      className={`relative flex w-full items-center ${
        isLeft ? 'md:justify-start' : 'md:justify-end'
      } justify-start`}
    >
      <div className="absolute left-[19px] md:left-1/2 md:-translate-x-1/2 z-10 h-4 w-4 rounded-full border-[3px] border-[hsl(270,50%,65%)] bg-background shadow-[0_0_12px_hsl(270,50%,65%,0.5)]" />

      <div
        className={`ml-12 md:ml-0 md:w-[calc(50%-2.5rem)] transition-all duration-700 ease-out ${
          visible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-6'
        } ${isLeft ? 'md:mr-auto md:pr-0' : 'md:ml-auto md:pl-0'}`}
        style={{ transitionDelay: `${index * 150}ms` }}
      >
        <div className="group relative rounded-xl border border-border/50 bg-card/60 backdrop-blur-md p-6 shadow-md hover:shadow-xl hover:scale-[1.03] transition-all duration-300">
          <div className="mb-3 flex items-center gap-2 text-[hsl(270,50%,65%)]">
            <Briefcase size={18} />
            <span className="text-xs font-medium uppercase tracking-wider text-muted-foreground">
              {item.period}
            </span>
          </div>
          <h3 className="text-lg font-bold text-foreground">{item.company}</h3>
          <p className="mt-1 text-sm text-muted-foreground">{item.role}</p>
        </div>
      </div>
    </div>
  );
}

export default function Experience() {
  return (
    <section id="experiencia" className="relative py-20 px-4">
      <div className="mx-auto max-w-4xl">
        <h2 className="mb-16 text-center text-3xl font-bold tracking-tight text-foreground md:text-4xl">
          Experiência
        </h2>

        <div className="relative flex flex-col gap-12">
          <div className="absolute left-[27px] md:left-1/2 md:-translate-x-1/2 top-0 bottom-0 w-[3px] bg-gradient-to-b from-[hsl(270,50%,65%)] via-[hsl(280,60%,75%)] to-[hsl(270,50%,65%,0.2)] rounded-full" />

          {experiences.map((item, i) => (
            <TimelineCard key={i} item={item} index={i} />
          ))}
        </div>
      </div>
    </section>
  );
}
